class Solution {
public:
    string resultingString(string s) {
        string res = "";
        for (char c : s) {
            if (!res.empty() && (res.back() == c || (res.back() == 'z' && c == 'a') || (res.back() == 'a' && c == 'z') || abs(res.back() - c) == 1)) {
                res.pop_back();
            } else {
                res.push_back(c);
            }
        }
        return res;
    }
};
